record_types.code:
type Contributor is
   record
      Author         : Text;
      authoring_Tool : Text;
   end record;

type Item is
   record
      Contributor : asset.Contributor;
      Created     : ada.Calendar.Time;
      Modified    : ada.Calendar.Time;
      Unit        : asset.Unit;
      up_Axis     : up_Direction;
   end record;

type Unit is
   record
      Name  : Text;
      Meter : Float;
   end record;
